,p_lov_name=>'LISTA GRUPPI ANAG_ART'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT      ',
'            ARTICOLO',
'        ,   DESCRIZIONE1',
