'                    (TIPO_ARTICOLO = ''Gruppi'' ',
'                AND (       ARTICOLO LIKE ''MG%'' ',
'                        OR  ARTICOLO LIKE ''MZ%'' ',
'                        OR ARTICOLO LIKE ''ML%'' ',
'                        OR ARTICOLO LIKE ''MT%'')',
'                AND STATO NOT LIKE ''%(O)%'') ',
