,p_lov_name=>'PROJECTS_WARRANTY'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT PROJECT, MACHINE_SN , COUNTRY_CODE, CUSTOMER_NAME',
'FROM REFERENCE_LIST_MACHINES ',
'LEFT JOIN ELENCO_MACCHINE_PROGETTI G',
'ON G.MATRICOLA = MACHINE_SN',
'WHERE ',
'         ((G.FINE_ESTENSIONE_GARANZIA >SYSDATE OR G.FINE_GARANZIA_STANDARD >SYSDATE )',
'         AND COUNTRY_CODE IN (  select A.CODE_NAZIONE',
'                            from NAZIONI_ASEGNATE_AGENTI A',
'                            INNER JOIN TB_CONTRATTI C',
'                            ON C.ID = A.TB_CONTRATTI_ID',
'                            where (C.CODICE_AGENTE = v(''FILIALE'')) OR v(''FILIALE'') =''SMI''))',
''))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_use_local_sync_table=>false
,p_query_owner=>'SMILE'
,p_query_table=>'ELENCO_MACCHINE_PROGETTI'
,p_return_column_name=>'PROJECT'
,p_display_column_name=>'PROJECT'
,p_group_sort_direction=>'ASC'
