 p_id=>wwv_flow_imp.id(188128450003040101)
,p_validation_name=>'Check DOCU'
,p_validation_sequence=>10
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT  ',
'        POS ',
'FROM componenti_usura2',
'INNER JOIN ANAGRAFICA_ARTICOLI',
'ON CODICE = ARTICOLO',
'WHERE       ',
'            matricola = :P5_SERIAL_NUMBER   ',
'',
'            and UPPER(articolO) = UPPER(:P5_CODE_ITEM) and UPPER(:P5_CODE_ITEM) NOT LIKE ''KZ%''',
'',
'',
'CONNECT BY PRIOR POS = POS_PADRE AND',
'           PRIOR ESE = ESE AND',
'           PRIOR DEP = DEP AND',
'           PRIOR TIPO = TIPO AND',
'           PRIOR NUM = NUM AND',
'           PRIOR PROGETTO = PROGETTO AND',
'           PRIOR MATRICOLA = MATRICOLA',
'START WITH POS_PADRE = 0 AND MATRICOLA = :P5_SERIAL_NUMBER'))
,p_validation_type=>'EXISTS'
,p_error_message=>'This code is not fit in the machine'
,p_validation_condition_type=>'NEVER'
,p_associated_item=>wwv_flow_imp.id(192121099329142939)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
