'/*',
'',
'select  USER_CREATION||''00''||ID,',
'       CREATION_DATE,',
'  --     USER_CREATION,',
'  --     USER_NAME,',
'  --     CUSTOMER,',
'  --     NC_TYPE,',
'       DECODE(STATUS,''0'',''NOT SEND'', ''1'',''SEND TO SMI'',''2'',''GUARANTEE REJECTED'',''3'',''ACCEPTED'',''4'',''SHIPPED'') AS STATUS,',
'  --     DATE_EXPIRATION,',
'       PROJECT',
' --      ID_NC',
'  from TB_NC_AFTERSALES',
' where :P0_USERNAME=USER_CREATION AND (STATUS > 1 )  */',
'',
'',
' SELECT     ''Project:  ''||PROJECT||''   Code requested:  '' ||CODE_ITEM list_title',
'        ,   DECODE(STATUS,''0'',''NOT SEND'', ''1'',''SEND TO SMI'',''2'',''GUARANTEE REJECTED'',''3'',''ACCEPTED'',''4'',''SHIPPED'')  LIST_BADGE',
'        ,   Aspm_Note_Item  list_text',
'        ,   '' '' list_class',
'        ,    null link',
'        ,    ''target="_blank"'' link_attr',
'        ,      null icon_color_class',
'        ,    ''fa fa-cloud'' icon_class',
'FROM RICHIESTE_GAR',
' where  UPPER(:P7_UTENTE)=UPPER(USER_CREATION) AND  (STATUS > 1)',
' ORDER BY STATUS DESC',
''))
