'select TB_NC_AFTERSALE_ID AS ID_NC,',
'       ID,',
'       SERIAL_NUMBER AS SELECTION,',
'       ''Qty:  ''||QTA||''  Code:   ''||CODE_ITEM  AS TITLE,',
'       ''NOTE SMI :  ''||ASPM_NOTE_ITEM AS DESCRIPTION,',
'       CREATION_DATE_ITEM,',
'       USER_CREATION_ITEM,',
'      -- STATUS_ITEM_REQUESTED AS ACTIONS,',
'       DATA_STATUS_UPDATE,',
'       GUARANTEE_TYPE,',
'       ASPM_NOTE_ITEM MISC,',
'       GUARANTEE_TYPE_REASON,',
'       ''NUM. ''||QTA AS QTA,',
'       ''<img src="#IMAGE_PREFIX#app_ui/img/icons/apex-edit-view.png" class="apex-edit-pencil" alt="">'' AS ICON_HTML,',
'       ''<img src="#IMAGE_PREFIX#app_ui/img/icons/apex-edit-view.png" class="apex-edit-pencil" alt="">'' AS SURVEY,',
'        case',
'           when STATUS_ITEM_REQUESTED = 2 then',
'           ''<div class="yellow-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED, 0, ''RECEIVED'',',
'                                         1, ''WAITING INFO'',',
'                                         2, ''PROCESSED'',',
'                                         3, ''REJECTED'',',
'                                         4, ''SHIPPED'')||''</div>'' ',
'            ',
'           when STATUS_ITEM_REQUESTED = 3 then',
'           ''<div class="red-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED, ',
'                                         0, ''RECEIVED'',',
'                                         1, ''WAITING INFO'',',
'                                         2, ''PROCESSED'',',
'                                         3, ''REJECTED'',',
'                                         4, ''SHIPPED'')||''</div>'' ',
'            ',
'            ',
'            else',
'            ''<div class="brown-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED,    0, ''RECEIVED'',',
'                                                                                                 1, ''WAITING INFO'',',
'                                                                                                 2, ''PROCESSED'',',
'                                                                                                 3, ''REJECTED'',',
'                                                                                                 4, ''SHIPPED'')|| ''</div>'' ',
'',
'        end   AS ACTIONS ',
'       ',
'',
'      ',
'  from TB_WARRANTY_REQUEST',
'  where TB_NC_AFTERSALE_Id=:P8_NC_ID'))
