,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT  A.ARTICOLO||'' (''||A.QUANTITA||'')  ''||G.DESCRIZIONE1||'' - ''||G.DESCRIZIONE2 AS ARTICOLO ,',
