wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(789082454891345264)
,p_plug_name=>'DISTINTA BASE'
,p_parent_plug_id=>wwv_flow_imp.id(802336330329735348)
,p_icon_css_classes=>'fa-wrench fa-3x fa-rotate-180 fam-minus fam-is-warning'
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(166480954003008025)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT  A.ARTICOLO,',
'        (SELECT DESCRIZIONE1 FROM ANAGRAFICA_ARTICOLI H WHERE A.ARTICOLO = H.ARTICOLO) AS DES1,',
'        (SELECT DESCRIZIONE2 FROM ANAGRAFICA_ARTICOLI H WHERE A.ARTICOLO = H.ARTICOLO) AS DES2,',
'        A.QUANTITA,',
'    --    A.MAN_PROG_ARTICOLO,',
'   --     A.MAN_USURA_ARTICOLO,',
'    --    A.RICAMBIO_CONSIGLIABILE,',
'        A.PADRE,	',
'        (SELECT DESCRIZIONE1 FROM ANAGRAFICA_ARTICOLI H WHERE A.PADRE = H.ARTICOLO) AS DES_PADRE1,',
'        (SELECT DESCRIZIONE2 FROM ANAGRAFICA_ARTICOLI H WHERE A.PADRE = H.ARTICOLO) AS DES2_PADRE2,',
'        A.MAN_PROG_PADRE,',
'        A.MAN_USURA_PADRE',
'',
'FROM TB_DIST_BASE A',
'',
'',
'START WITH A.parent_id IS NULL',
'CONNECT BY PRIOR A.id_ITEM = A.parent_id',
'',
'',
'-- select distinct',
'--        C005 AS QUANTITA,',
'--        C001 AS CODE,',
'--        C002 AS TIPO,',
'--        C003 AS GRUPPO_PADRE,',
'--        C004 AS ORE_PROGRAMMATE,',
'--        C007 AS DESCRIZIONE_1,',
'--        C008 AS DESCRIZIONE_2,',
'--        N001 AS PREZZO_LISTINO,',
'--      --  '' <a href="'' || (SELECT NVL(LINK_DISEGNO(C001),''#'') FROM DUAL)  || ''" target="_blank"><span class="t-Icon fa fa-file-pdf-o" aria-hidden="true"></span><span class="t-Button-label"></span></a>'' BUTTON,',
'--        ''<span class="t-Icon fa fa-file-pdf-o" aria-hidden="true"></span><span class="t-Button-label"></span></a>'' AS PDF,',
'--        ''PDF'' AS LINK',
'        ',
'--   from APEX_COLLECTIONS',
' ',
'--   where     COLLECTION_NAME = ''ARTICOLI_GENERICI''',
'--    --     and (C004 <> ''Generico'' AND C004 <> ''No'' or C004 is null)',
'--         AND  INSTR('':''||:P9_TIPO||'':'', '':'' || C002 || '':'') > 0',
'--         and C002 <> ''Generico''',
'',
'--  UNION ALL',
'',
'-- select  DISTINCT',
'--         C005 AS QUANTITA,',
'--         C001 AS CODE,',
'--         C002 AS TIPO,',
'--         C003 AS GRUPPO_PADRE,',
'--         C004 AS ORE_PROGRAMMATE,',
'--         C007 AS DESCRIZIONE_1,',
'--         C008 AS DESCRIZIONE_2,',
'--         N001 AS PREZZO_LISTINO,',
'--    --     '' <a href="'' || (SELECT NVL(LINK_DISEGNO(C001),''#'') FROM DUAL)  || ''" target="_blank"><span class="t-Icon fa fa-file-pdf-o" aria-hidden="true"></span><span class="t-Button-label"></span></a>'' BUTTON,',
'--             ''<span class="t-Icon fa fa-file-pdf-o" aria-hidden="true"></span><span class="t-Button-label"></span></a>'' AS PDF,',
'--         ''PDF'' AS LINK',
'    ',
'-- from APEX_COLLECTIONS',
' ',
'-- where --    COLLECTION_NAME = ''ARTICOLI_GENERICI''',
'--   --        and (C004 = ''Generico'' AND C004 <> ''No'' or C004 is null)',
'--          INSTR('':''||:P9_MAN_PROG||'':'', '':'' || C004 || '':'') > 0  AND C002 = ''Generico''',
'',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P9_CODICE_PADRE'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
