wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(193584283713521102)
,p_name=>'Search Results'
,p_template=>wwv_flow_imp.id(166480954003008025)
,p_display_sequence=>20
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--altRowsDefault:t-Report--rowHighlight:t-Report--horizontalBorders:t-Report--hideNoPagination'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'       A.MATRICOLA,',
'       B.CUSTOMER_CODE,',
'       UPPER(B.CUSTOMER_NAME) AS CUSTOMER_NAME,',
'       UPPER(B.COUNTRY) AS COUNTRY,',
'       CASE',
'       WHEN STATE_MACHINE = ''V'' THEN ''IN PRODUCTION'' ELSE ''OUT OF PRDUCTION''',
'       END STATE_MACHINE',
'FROM componenti_usura2 A',
'INNER JOIN REFERENCE_LIST_MACHINES B ON A.MATRICOLA = B.MACHINE_SN',
'WHERE a.codice = :CODICE ',
'  AND EXISTS (',
'      SELECT 1',
'      FROM REFERENCE_LIST_MACHINES RLM',
'      LEFT JOIN ELENCO_MACCHINE_PROGETTI G ON G.MATRICOLA = RLM.MACHINE_SN',
'      WHERE RLM.MACHINE_SN = A.MATRICOLA',
'        AND (RLM.COUNTRY_CODE IN (',
'                SELECT A.CODE_NAZIONE',
'                FROM NAZIONI_ASEGNATE_AGENTI A',
'                INNER JOIN TB_CONTRATTI C ON C.ID = A.TB_CONTRATTI_ID',
'                WHERE C.CODICE_AGENTE = :BRANCH',
'            ) OR :BRANCH = ''SMI'')',
'        AND RLM.DIVISION_CODE <> ''SB''',
'  )',
'ORDER BY A.MATRICOLA ASC;'))
,p_read_only_when_type=>'ITEM_IS_NOT_NULL'
,p_read_only_when=>'CODICE'
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'CODICE,BRANCH'
,p_lazy_loading=>false
,p_query_row_template=>wwv_flow_imp.id(166501397206008018)
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_no_data_found=>'sorry I could find nothing!'
,p_query_num_rows_type=>'ROW_RANGES_IN_SELECT_LIST'
,p_pagination_display_position=>'BOTTOM_LEFT'
,p_csv_output=>'Y'
,p_csv_output_link_text=>'Download'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_exp_filename=>'&CODICE.'
,p_plug_query_exp_separator=>';'
,p_plug_query_exp_enclosed_by=>'"'
,p_plug_query_strip_html=>'N'
);
