'            ,   DEPOSITO',
'            ,   TIPO_ORDINE',
'            ,   NUMERO_ORDINE      ',
'            ,   DECODE(TVEND_CO ,   ''3-C/to Riparazione Garanzia'',''Repair under Guarantee''',
