,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select    ',
'                MATRICOLA',
'            ,   ESERCIZIO||''/''||DEPOSITO||''/''||TIPO_ORDINE||''/''||NUMERO_ORDINE as order_number',
'            ,   DECODE(TVEND_CO ,   ''3-C/to Riparazione Garanzia'',''Repair under Guarantee''',
'                                ,   ''5-C/to Sostituzione Garanzia'',''Guarantee replacement''',
'                                ,   ''7-Completamento Fornitura'',''Supply Completing'') AS TVEND_CO',
