'            ,   QTA_EVASA',
'            ,   ''Code: ''||ARTICOLO as LIST_TITLE',
'            ,   ''Description: ''||DESCRIZIONE1|| ''   ''||DESCRIZIONE2 as LIST_TEXT',
'            ,   nvl(decode(STATO_EVASIONE_RIGA, ''S'', ''YES''), ''NO'') AS icon',
'            ,   DATA_CONSEGNA_CONFERMATA',
'          ',
'            ,   ''fa fa-package'' icon_class',
'    ',
'    from TB_ARTICOLI  ',
'    where           matricola = :P22_MATRICOLA',
'            and     (TVEND_CO LIKE ''3-%'' OR TVEND_CO LIKE ''5%'' OR TVEND_CO LIKE ''7%'')',
