,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select TB_NC_AFTERSALE_ID,',
'       ID,',
'       SERIAL_NUMBER,',
'       CODE_ITEM EVENT_TITLE ,',
'       ITEM_TYPE,',
'       CREATION_DATE_ITEM AS EVENT_DATE,',
'       USER_CREATION_ITEM AS USER_NAME,',
'       case',
'       when STATUS_ITEM_REQUESTED = 2 then',
'       ''<div class="yellow-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED, 0, ''NOT SENT'',',
'                                     1, ''MISSING INFO'',',
'                                     2, ''PROCESSED'',',
'                                     3, ''REJECTED'',',
'                                     4, ''SHIPPED'')||''</div>''||''fa fa-clock-o'' ',
'        ',
'       when STATUS_ITEM_REQUESTED = 3 then',
'       ''<div class="red-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED, 0, ''NOT SENT'',',
'                                     1, ''MISSING INFO'',',
'                                     2, ''PROCESSED'',',
'                                     3, ''REJECTED'',',
'                                     4, ''SHIPPED'')||''</div>'' ',
'        ',
'        ',
'        else',
'        ''<div class="brown-background no-parent-padding">''||DECODE(STATUS_ITEM_REQUESTED, 0, ''NOT SENT'',',
'                                     1, ''MISSING INFO'',',
'                                     2, ''PROCESSED'',',
'                                     3, ''REJECTED'',',
'                                     4, ''SHIPPED'')||''</div>''',
'',
'        end   AS EVENT_TYPE , ',
'       case STATUS_ITEM_REQUESTED ',
'                when ''0'' then ''fa fa-clock-o''',
'                when ''2'' then ''fa fa-check-circle-o''',
'                when ''3'' then ''fa fa-exclamation-circle''',
'                when ''1'' then ''fa fa-exclamation-triangle''',
'       end event_icon, ',
'       DATA_STATUS_UPDATE,',
'       GUARANTEE_TYPE,',
'       ASPM_NOTE_ITEM AS EVENT_DESC ,',
'       GUARANTEE_TYPE_REASON ,',
'       QTA,',
'       substr(USER_CREATION_ITEM,0,2) user_avatar,',
'       DATA_VISUAL,',
'       ''<button type="button" title="" aria-label="" class="t-Button t-Button--noLabel t-Button--icon t-Button--large t-Button--primary"><span aria-hidden="true" class="t-Icon fa fa-envelope-bookmark"></span></button>'' LINK',
'  from TB_WARRANTY_REQUEST',
' where :P27_TB_AFTERSALES_NC_ID = TB_NC_AFTERSALE_ID'))
